{
    "space": "{{$hJmYZWKFOW26n5E1.nFdHUxLCQ0jpMHOd$}}",
    "ngql": "MATCH (l1:entity)-[:rel]->(l2:entity) WHERE l1.entity.lvl == 1 AND l2.entity.lvl == 2 RETURN l1.entity.source_id AS l1_source_id, l1.entity.name AS l1_name, l2.entity.source_id AS l2_source_id, l2.entity.name AS l2_name ORDER BY l1_source_id, l2_source_id;"
}

async function main({ httpRawResponse }) {
   const raw =
     httpRawResponse &&
     typeof httpRawResponse === "object" &&
     httpRawResponse.httpRawResponse &&
     typeof httpRawResponse.httpRawResponse === "object"
       ? httpRawResponse.httpRawResponse
       : httpRawResponse;

   const stdout = typeof raw?.stdout === "string" ? raw.stdout : "";
   if (!stdout) {
     return { summary_text: "没有可解析的查询结果。" };
   }

   const stripQuotes = (v) =>
     String(v ?? "")
       .trim()
       .replace(/^"(.*)"$/, "$1");

   const parseTableRow = (line) =>
     line
       .split("|")
       .slice(1, -1)
       .map((c) => stripQuotes(c.trim()));

   const lines = stdout.split(/\r?\n/).map((s) => s.trim());
   const tableLines = lines.filter((l) => l.startsWith("|") && l.endsWith("|"));

   const rows = [];
   for (const line of tableLines) {
     const cells = parseTableRow(line);
     if (cells.length < 4) continue;
     if (cells[0] === "l1_source_id" && cells[1] === "l1_name") continue;
     if (!/^\d+$/.test(cells[0]) || !/^\d+$/.test(cells[2])) continue;

     rows.push({
       l1_source_id: Number(cells[0]),
       l1_name: cells[1],
       l2_source_id: Number(cells[2]),
       l2_name: cells[3]
     });
   }

   if (rows.length === 0) {
     return { summary_text: "未解析到一级/二级故障映射数据。" };
   }

   const l1Map = new Map();
   for (const r of rows) {
     const key = String(r.l1_source_id);
     if (!l1Map.has(key)) {
       l1Map.set(key, {
         l1_source_id: r.l1_source_id,
         l1_name: r.l1_name,
         l2Map: new Map()
       });
     }
     l1Map.get(key).l2Map.set(String(r.l2_source_id), r.l2_name);
   }

   const l1List = Array.from(l1Map.values())
     .sort((a, b) => a.l1_source_id - b.l1_source_id)
     .map((item) => {
       const l2Names = Array.from(item.l2Map.values());
       return {
         l1_name: item.l1_name,
         l2_count: l2Names.length,
         l2_names: l2Names
       };
     });

   const l1Names = l1List.map((x) => x.l1_name);
   const total = l1List.reduce((s, x) => s + x.l2_count, 0);
   const detail = l1List
     .map((x) => `${x.l1_name}有${x.l2_count}个二级故障：${x.l2_names.join("、")}`)
     .join("；");

   const summary_text =
     `一级故障有：${l1Names.join("、")}。` +
     `\n其中：${detail}。` +
     `\n合计二级故障映射${total}条。`;

   return { summary_text };
 }

