async function main({ httpRawResponse }) {
    // 1. 兼容多种响应结构，提取 stdout
    const raw =
      httpRawResponse &&
      typeof httpRawResponse === "object" &&
      httpRawResponse.httpRawResponse &&
      typeof httpRawResponse.httpRawResponse === "object"
        ? httpRawResponse.httpRawResponse
        : httpRawResponse;

    const stdout = typeof raw?.stdout === "string" ? raw.stdout : "";

    // 2. 默认兜底文案（修复了原代码中字符串跨行导致的 Unexpected EOF 报错）
    const fallback = "当前二级故障：未知。故障原因：未检索到。应对措施：未检索到。故障现象：未检索到。故障后果：未检索到。安全风险：未检索到。应急资源：未检索到。";

    if (!stdout || !stdout.includes("|")) {
      return { result: fallback };
    }

    // 3. 辅助函数：去除引号和空格
    function stripQuotes(v) {
      return String(v == null ? "" : v).trim().replace(/^"(.*)"$/, "$1");
    }

    // 4. 解析表格行
    function parseRow(line) {
      return line
        .split("|")
        .slice(1, -1)
        .map(function (c) {
          return stripQuotes(c.trim());
        });
    }

    const lines = stdout.split(/\r?\n/).map(function (s) {
      return s.trim();
    });

    // 过滤出真正的表格行（跳过 ASCII 分隔线）
    const tableLines = lines.filter(function (l) {
      return l.startsWith("|") && l.endsWith("|") && !l.includes("+--");
    });

    if (tableLines.length < 2) {
      return { result: fallback };
    }

    const rows = tableLines.map(parseRow);
    const header = rows[0];
    const body = rows.slice(1);

    // 5. 定位列索引（对应你 nGQL 中的 AS name 和 AS node_desc）
    const idxName = header.indexOf("name");
    const idxNodeDesc = header.indexOf("node_desc");

    if (idxName < 0) {
      return { result: fallback };
    }

    // 6. 初始化分类容器
    const reason = [];
    const measure = [];
    const symptom = [];
    const consequence = [];
    const risk = [];
    const resource = [];
    const other = [];

    let faultName = "";

    // 7. 遍历数据并分类
    body.forEach(function (r) {
      const name = (r[idxName] || "").trim();
      const desc = idxNodeDesc >= 0 ? (r[idxNodeDesc] || "").trim() : "";

      if (!name) return;

      // 自动提取故障主体名称（取第一个关联节点的名称前缀）
      if (!faultName) {
        faultName = name.split('-')[0];
      }

      const item = desc ? (name + "：" + desc) : name;

      // 根据业务关键词分类
      if (name.indexOf("故障原因") >= 0) reason.push(item);
      else if (name.indexOf("应对措施") >= 0) measure.push(item);
      else if (name.indexOf("故障现象") >= 0) symptom.push(item);
      else if (name.indexOf("故障后果") >= 0) consequence.push(item);
      else if (name.indexOf("安全风险") >= 0) risk.push(item);
      else if (name.indexOf("应急资源") >= 0) resource.push(item);
      else other.push(item);
    });

    // 格式化辅助函数
    function fmt(arr, emptyText) {
      return arr.length > 0 ? arr.join("；") : emptyText;
    }

    // 8. 组装最终结果
    const result =
      "当前二级故障：" + (faultName || "未知") + "。" +
      "故障原因：" + fmt(reason, "未检索到") + "。" +
      "应对措施：" + fmt(measure, "未检索到") + "。" +
      "故障现象：" + fmt(symptom, "未检索到") + "。" +
      "故障后果：" + fmt(consequence, "未检索到") + "。" +
      "安全风险：" + fmt(risk, "未检索到") + "。" +
      "应急资源：" + fmt(resource, "未检索到") + "。" +
      "其他相关节点：" + fmt(other, "无") + "。";

    return { result: result };
}

