async function main({ httpRawResponse }) {
    // 1. 兼容性提取：判断输入是纯字符串还是 FastGPT 的 HTTP 响应对象
    let stdout = "";
    if (typeof httpRawResponse === "string") {
        stdout = httpRawResponse;
    } else if (httpRawResponse && typeof httpRawResponse === "object") {
        // 尝试获取不同层级下的 stdout
        stdout = httpRawResponse.stdout || 
                 httpRawResponse.httpRawResponse?.stdout || 
                 "";
    }

    if (!stdout) return { devicespace: "" };

    // 2. 去掉引号的辅助函数
    const stripQuotes = (v) =>
      String(v ?? "")
        .trim()
        .replace(/^"(.*)"$/, "$1");

    // 3. 解析表格
    const lines = stdout.split(/\r?\n/).map((s) => s.trim());
    // 仅保留表格内容行：| ... |
    const tableLines = lines.filter((l) => l.startsWith("|") && l.endsWith("|"));

    if (tableLines.length < 2) return { devicespace: "" };

    // 将行转为数组
    const rows = tableLines.map(line => 
        line.split("|").slice(1, -1).map(c => stripQuotes(c))
    );

    const header = rows[0];
    const nameIdx = header.indexOf("Name");
    if (nameIdx < 0) return { devicespace: "" };

    // 4. 提取数据行并过滤 llmkg_ 前缀
    const deviceSpaces = rows.slice(1)
      .map((r) => r[nameIdx])
      .filter((s) => s && s.startsWith("llmkg_"));

    // 5. 返回结果（按你要求，只要一个字段）
    // 如果需要数组，直接返回 deviceSpaces；如果需要字符串，用 .join(",")
    return {
      devicespace: deviceSpaces.join(",")
    };
}
